__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"default",{enumerable:!0,get:function(){return n}});var n={title:{devanagari:'\u091c\u0928\u094d\u092e\u0926\u093f\u0928 \u092a\u0942\u091c\u093e',roman:'Janam Din Puja',english:'Birthday Puja of Kashmiri Pandits'},description:'The birthday is celebrated on the lunar tithi of the date of birth. Te\'hr (turmeric rice) is the traditional bhog. This puja invokes blessings of seven divine Rishis (Devreshis) through Nariwan with seven knots.',samagri:[{id:'s1',name:{devanagari:'\u092f\u091c\u094d\u091e\u094b\u092a\u0935\u0940\u0924',roman:'Yagnopavit',english:'Sacred Thread'},description:'For initiated males (Mekhal)',category:'essential'},{id:'s2',name:{devanagari:'\u092e\u094c\u0932\u0940 / \u0928\u093e\u0930\u093f\u0935\u0928',roman:'Mawli / Nariwan',english:'Sacred Thread for Wrist'},description:'Cut pieces for all family members + longer piece for birthday person',category:'essential'},{id:'s3',name:{devanagari:'\u0915\u0947\u0938\u0930 \u0915\u093e \u0932\u0947\u092a',roman:'Saffron Paste (Tika)',english:'Saffron Tilak'},description:'Made by rubbing chandan and saffron on stone',category:'essential'},{id:'s4',name:{devanagari:'\u0930\u0924\u0928\u0926\u0940\u092a',roman:'Ratandeep',english:'Oil Lamp'},description:'A lit lamp, preferably in a plate',category:'essential'},{id:'s5',name:{devanagari:'\u0905\u0917\u0930\u092c\u0924\u094d\u0924\u0940 / \u0927\u0942\u092a',roman:'Agarbati / Doop',english:'Incense'},description:'Incense sticks or doop',category:'essential'},{id:'s6',name:{devanagari:'\u0917\u0923\u0947\u0936 \u0935 \u0935\u093f\u0937\u094d\u0923\u0941 \u092b\u094b\u091f\u094b',roman:'Ganesh & Vishnu Photo',english:'Photos of Deities'},description:'Photo of Ganesh and Vishnu or Krishna',category:'essential'},{id:'s7',name:{devanagari:'\u0918\u0902\u091f\u093e',roman:'Ganta',english:'Bell'},description:'Puja bell',category:'essential'},{id:'s8',name:{devanagari:'\u0936\u0902\u0916',roman:'Shankh',english:'Conch Shell'},description:'Optional',category:'optional'},{id:'s9',name:{devanagari:'\u0924\u093e\u091c\u093c\u093e \u092a\u093e\u0928\u0940',roman:'Fresh Water',english:'Fresh Water in Pot'},description:'In a clean pot',category:'essential'},{id:'s10',name:{devanagari:'\u0925\u093e\u0932\u093f\u092f\u093e\u0901',roman:'Thalis/Plates',english:'Plates'},description:'A few plates and an empty pot for nirmal (used water)',category:'essential'},{id:'s11',name:{devanagari:'\u092b\u0942\u0932 \u0935 \u0905\u0930\u094d\u0918\u094d\u092f',roman:'Flowers & Arghya',english:'Flowers & Rice Mix'},description:'Loose flowers and arghya (mixture of loose flowers and wet rice)',category:'essential'},{id:'s12',name:{devanagari:'\u091c\u093c\u0902\u0917',roman:'Zang',english:'Rice Offering'},description:'Rice in cup with salt (in paper), coin, and fruit on top. Given to priest or temple.',category:'essential'},{id:'s13',name:{devanagari:'\u0926\u0930\u094d\u092d\u093e / \u0935\u093f\u0937\u094d\u0920\u0941\u0930',roman:'Darbha / Vishthur',english:'Sacred Grass'},description:'Darbha grass, Vishthur is darbha with a knot in middle',category:'essential'},{id:'s14',name:{devanagari:'\u092a\u0935\u093f\u0924\u094d\u0930\u0940',roman:'Pavitri',english:'Ring of Dhurva Grass'},description:'Ring made of dhurva grass or metal (silver/gold) for anamika finger',category:'essential'},{id:'s15',name:{devanagari:'\u0915\u093e\u0932\u0947 \u0924\u093f\u0932',roman:'Black Sesamum (Til)',english:'Black Sesame Seeds'},description:'For Bhu Shuddhi step',category:'optional'},{id:'p1',name:{devanagari:'\u091c\u0932',roman:'Jal',english:'Water'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p2',name:{devanagari:'\u0926\u0942\u0927',roman:'Dudh',english:'Milk'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p3',name:{devanagari:'\u0926\u0939\u0940',roman:'Dahi',english:'Curd/Yogurt'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p4',name:{devanagari:'\u0918\u0940',roman:'Ghee',english:'Clarified Butter'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p5',name:{devanagari:'\u0936\u0939\u0926',roman:'Shahad',english:'Honey'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p6',name:{devanagari:'\u0936\u0915\u094d\u0915\u0930',roman:'Shakar',english:'Raw Sugar'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p7',name:{devanagari:'\u0938\u0930\u0938\u094b\u0902',roman:'Sarshap',english:'Yellow Mustard Seeds'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p8',name:{devanagari:'\u0932\u093e\u091c\u093e',roman:'Laja',english:'Baked Paddy'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p9',name:{devanagari:'\u0938\u0930\u094d\u0935\u094c\u0937\u0927\u093f',roman:'Sarvaushadi',english:'Mixture of Herbs'},description:'Available from puja shops',category:'panchdashang'},{id:'p10',name:{devanagari:'\u091a\u0928\u094d\u0926\u0928 / \u0915\u0947\u0938\u0930',roman:'Chandan / Saffron',english:'Sandalwood / Saffron Paste'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p11',name:{devanagari:'\u0938\u094b\u0928\u093e / \u091a\u093e\u0901\u0926\u0940',roman:'Gold / Silver',english:'Gold/Silver Ring'},description:'Symbolic dip of ring with stone in water',category:'panchdashang'},{id:'p12',name:{devanagari:'\u092b\u0942\u0932',roman:'Phool',english:'Flowers (for Snan)'},description:'For Panchdashang Snan',category:'panchdashang'},{id:'p13',name:{devanagari:'\u0935\u093f\u0937\u094d\u0920\u0941\u0930',roman:'Vashthur',english:'Knotted Darbha'},description:'For shortage of any item add flowers',category:'panchdashang'},{id:'f1',name:{devanagari:"\u0924\u0947'\u0939\u0930",roman:"Te'hr",english:'Turmeric Rice'},description:'Cooked rice dyed yellow with turmeric \u2013 the traditional bhog',category:'food'},{id:'f2',name:{devanagari:'\u0926\u0939\u0940',roman:'Dahi',english:'Curd/Yogurt for Bhog'},description:'Traditionally offered as bhog',category:'food'}],parts:[{id:'A',title:{devanagari:'\u0927\u0942\u092a \u0926\u0940\u092a \u092a\u0942\u091c\u093e',roman:'Doop Deep Puja',english:'Preliminary Ritual (Purva Bhaga)'},subtitle:'15 steps performed in all Kashmiri Pandit pujas. Shortcut: skip steps 8, 9, 11, 12, 15.',steps:[{id:'A1',number:1,title:{devanagari:'\u0906\u091a\u092e\u0928',roman:'Achman',english:'Symbolic Purification'},instructions:'Sip a small quantity of water (1-2 cc) from your right hand palm three times while reciting the mantra.',actionDescription:'Sip water from right palm 3 times',mantra:{devanagari:'\u0950 \u0936\u0902 \u0928\u094b \u0926\u0947\u0935\u0940\u0930\u092d\u093f\u0937\u094d\u091f\u092f\u0947 \u0906\u092a\u094b \u092d\u0935\u0928\u094d\u0924\u0941 \u092a\u0940\u0924\u092f\u0947\u0964 \u0936\u0902\u092f\u094b\u0930\u092d\u093f \u0938\u094d\u0930\u0935\u0928\u094d\u0924\u0941 \u0928\u0903\u0964',roman:'Om Sham No Devir Abhishtye Apo Bhvantu Pitye. Shamyor Abhi Srvantu Nah.',english:'Oh God, may the divine waters be propitious to us for the fulfillment of desires and for our drinking. May gods shower on us joy and welfare.'},isOptional:!1,duration:30},{id:'A2',number:2,title:{devanagari:'\u0938\u0902\u0915\u0932\u094d\u092a',roman:'Sankalp',english:'Solemn Vow'},instructions:'Hold a handful of flowers. Recite the sankalp declaring the date, gotra, and purpose of the puja. The fields marked ____ will be auto-filled with your details.',actionDescription:'Hold flowers in hands and recite vow',mantra:{devanagari:'\u0950 \u0924\u0924\u094d \u0938\u0924\u094d \u092c\u094d\u0930\u0939\u094d\u092e \u0905\u0927\u094d\u092f \u0924\u093e\u0935\u0924\u094d \u0924\u093f\u0925\u094c \u0905\u0926\u094d\u092f\u0947 ___\u092e\u093e\u0938\u0947 ___\u092a\u0915\u094d\u0937\u0947 ___\u0924\u093f\u0925\u094c ___\u0935\u093e\u0930\u0947 ___\u0915\u093e\u0932\u0947 ___\u0917\u094b\u0924\u094d\u0930\u0947 \u0905\u0939\u0902 ___\u091c\u0928\u094d\u092e \u0926\u093f\u0935\u0938\u093f \u092a\u0942\u091c\u093e \u0915\u0930\u094d\u092e \u0915\u0930\u093f\u0937\u094d\u092f\u0947\u0964',roman:'Om Tat Sat Brahma Adhy Tavat Tithou Adye ___Masey ___Pakshey ___Tithou ___Varey ___Kale ___Gotrey Aham ___Janam Divasy Puja Karm Karishye.',english:'On this day (date/month/tithi/day), I of ___ gotra, hereby solemnly vow to perform the Birthday Puja for ___.'},isOptional:!1,duration:60},{id:'A3',number:3,title:{devanagari:'\u0906\u0938\u0928 \u0936\u094b\u0927\u0928',roman:'Aasan Shodan',english:'Cleaning the Seat'},instructions:'Clean the seat of worship symbolically with darbha. Place water in a cup (pranipatr) with Vishthur. Consecrate water by reciting Viniyoga, then sprinkle water over the seat.',actionDescription:'Sprinkle water on seat with Vishthur',mantra:{devanagari:'\u0950 \u092a\u0943\u0925\u093f\u0935\u094d\u092f\u0948 \u0924\u094d\u0935\u092f\u093e \u0927\u0943\u0924\u093e \u0932\u094b\u0915\u093e \u0926\u0947\u0935\u093f \u0924\u094d\u0935\u0902 \u0935\u093f\u0937\u094d\u0923\u0941\u0928\u093e \u0927\u0943\u0924\u093e\u0964 \u0924\u094d\u0935\u0902 \u091a \u0927\u093e\u0930\u092f \u092e\u093e\u092e\u094d \u0926\u0947\u0935\u093f \u092a\u0935\u093f\u0924\u094d\u0930\u0902 \u0915\u0941\u0930\u0941 \u091a\u093e\u0938\u0928\u092e\u094d\u0964',roman:'Om Prithivyai Tvya Drita Loka Devi Tvm Vishnuna Drta. Tvm Ch Dharaya Mam Devi Pvitrm Kuru Chasnm.',english:'O Mother Earth, the worlds are supported by you and you are supported by Lord Vishnu. O Goddess Prithvi, support me too and purify my seat.'},subSteps:[{id:'A3a',label:'Viniyoga (Naming the Rishi)',instructions:'Recite the Viniyoga mantra to name the Rishi, metre, and deity of this mantra.',mantra:{devanagari:'\u0905\u0938\u094d\u092f \u0936\u094d\u0930\u0940 \u0906\u0938\u0928 \u0936\u094b\u0927\u0928 \u092e\u0928\u094d\u0924\u094d\u0930\u0938\u094d\u092f \u092e\u0947\u0930\u0941\u092a\u0943\u0937\u094d\u0920 \u090b\u0937\u093f \u0938\u0942\u0924\u0932 \u091b\u0928\u094d\u0926\u0903 \u0915\u0942\u0930\u094d\u092e\u094b \u0926\u0947\u0935\u0924\u093e \u0906\u0938\u0928 \u0936\u094b\u0927\u0928 \u0935\u093f\u0928\u093f\u092f\u094b\u0917\u0903',roman:'Asy Shri Asn Shodn Mntrsy Meruprshth Rishi Sutlm Chhndh Kurmo Devta Asan Shodn Viniyogh',english:'For purification of the seat, Meru Preshth is the sage, Kurma (tortoise) is the deity, Sutla is the metre.'}}],isOptional:!1,duration:45},{id:'A4',number:4,title:{devanagari:'\u092a\u0943\u0925\u093f\u0935\u0940 \u092a\u0942\u091c\u0928',roman:'Prithvi Pujan',english:'Worship of Mother Earth'},instructions:'Apply tilak, arghya, and flowers to the floor in front while reciting.',actionDescription:'Apply tilak to floor',mantra:{devanagari:'\u092a\u094d\u0930\u0940\u0902 \u092a\u0943\u0925\u093f\u0935\u094d\u092f\u0948 \u0906\u0927\u093e\u0930 \u0936\u0915\u094d\u0924\u094d\u092f\u0948 \u0938\u092e\u093e\u0932\u092d\u0928\u0902 \u0917\u0928\u094d\u0927\u094b \u0928\u092e\u0903 \u0905\u0930\u094d\u0917\u094b \u0928\u092e\u0903 \u092a\u0941\u0937\u094d\u092a\u0902 \u0928\u092e\u0903',roman:'Prim Prithiviyai Adhar Shaktyai Smalubnm Gandho Nmh Arghyo Nmh Pushpm Nmh',english:'I bow to Mother Earth who is the support of Primal Energy and offer my salutations with tilak, arghya, and flowers.'},isOptional:!1,duration:30},{id:'A5',number:5,title:{devanagari:'\u0906\u0915\u093e\u0936 \u092a\u0942\u091c\u0928',roman:'Aakash Pujan',english:'Worship of Sky'},instructions:'Hold tilak, arghya, and flowers in fingers, point towards sky, then put in nirmal.',actionDescription:'Offer tilak towards sky',mantra:{devanagari:'\u0938\u094d\u0915\u0928\u094d\u0926 \u0906\u0927\u093e\u0930 \u0936\u0915\u094d\u0924\u094d\u092f\u0948 \u0938\u092e\u093e\u0932\u092d\u0928\u0902 \u0917\u0928\u094d\u0927\u094b \u0928\u092e\u0903 \u0905\u0930\u094d\u0917\u094b \u0928\u092e\u0903 \u092a\u0941\u0937\u094d\u092a\u0902 \u0928\u092e\u0903',roman:'Sknd Adhar Shktyai Smalubnm Gndho Nmh Argo Nmh Pushpm Nmh',english:'To Sky, the support of Prime Energy, I offer salutations with tilak, arghya, and flowers.'},isOptional:!1,duration:30},{id:'A6',number:6,title:{devanagari:'\u0917\u0923\u0947\u0936 \u092a\u0942\u091c\u0928',roman:'Ganesh Pujan',english:'Seeking Blessings of Lord Ganesh'},instructions:'Apply tilak, arghya, and flowers to Ganesh photo/idol while reciting the mantra.',actionDescription:'Apply tilak to Ganesh',mantra:{devanagari:'\u0950 \u0936\u0941\u0915\u094d\u0932\u093e\u092e\u094d\u092c\u0930\u0927\u0930\u0902 \u0935\u093f\u0937\u094d\u0923\u0941\u0902 \u0936\u0936\u093f\u0935\u0930\u094d\u0923\u0902 \u091a\u0924\u0941\u0930\u094d\u092d\u0941\u091c\u092e\u094d\u0964 \u092a\u094d\u0930\u0938\u0928\u094d\u0928 \u0935\u0926\u0928\u0902 \u0927\u094d\u092f\u093e\u092f\u0902 \u0938\u0930\u094d\u0935 \u0935\u093f\u0918\u094d\u0928\u094b\u092a \u0936\u093e\u0928\u094d\u0924\u092f\u0947\u0964',roman:'Om Shuklmber Dhrm Vishnu, Shshivrnm Chturbhujam. Prsnn Vdnm Dyaye Srv Vignop Shantiyai.',english:'I pray to Lord Ganesh, whose clothes are white like sky, who is bright like the Moon, who has four arms and is always happy. Even gods worship Him for removal of obstacles.'},isOptional:!1,duration:45},{id:'A7',number:7,title:{devanagari:'\u0917\u0941\u0930\u0941 \u092a\u0942\u091c\u093e',roman:'Guru Puja',english:'Seeking Blessings of Guru'},instructions:'Apply tilak, arghya, and flowers to Guru while reciting. Trinity of Brahma, Vishnu, Mahesh are the first gurus.',actionDescription:'Apply tilak while reciting Guru mantra',mantra:{devanagari:'\u0917\u0941\u0930\u0941\u0930\u094d\u092c\u094d\u0930\u0939\u094d\u092e\u093e \u0917\u0941\u0930\u0941\u0930\u094d\u0935\u093f\u0937\u094d\u0923\u0941\u0903 \u0917\u0941\u0930\u0941\u0930\u094d\u0926\u0947\u0935\u094b \u092e\u0939\u0947\u0936\u094d\u0935\u0930\u0903\u0964 \u0917\u0941\u0930\u0941\u0903 \u0938\u093e\u0915\u094d\u0937\u093e\u0924\u094d \u092a\u0930\u092c\u094d\u0930\u0939\u094d\u092e \u0924\u0938\u094d\u092e\u0948 \u0936\u094d\u0930\u0940 \u0917\u0941\u0930\u0935\u0947 \u0928\u092e\u0903\u0964 \u0917\u0941\u0930\u094d\u0935\u0947 \u0928\u092e\u0903 \u092a\u0930\u092e \u0917\u0941\u0930\u094d\u0935\u0947 \u0928\u092e\u0903 \u092a\u0930\u092e\u093e\u091a\u093e\u0930\u094d\u092f \u0928\u092e\u0903\u0964 \u0906\u0926\u093f \u0938\u093f\u0926\u094d\u0927\u093f\u092d\u094d\u092f\u094b \u0928\u092e\u0903\u0964',roman:'Gurur Brahma Gurur Vishnu Gurudevo Maheshvara. Guruh Sakshat Parbrahm Tasmai Shri Gurave Namah. Gurve Namah Param Gurve Namah Parmacherya Namah. Adhi Siddhi Byo Namah.',english:'Guru is Brahma, Vishnu, and Mahesh. He is Omnipresent. I bow to the Supreme Master and source of all right actions.'},isOptional:!1,duration:45},{id:'A8',number:8,title:{devanagari:'\u0905\u0902\u0917\u0928\u094d\u092f\u093e\u0938',roman:'Angnyas',english:'Assigning Body Parts to Gods'},instructions:'Hold 2 pieces of darbha in third fingers of both hands. Touch body parts as indicated while reciting mantras.',actionDescription:'Touch fingers and body parts with mantras',isOptional:!0,subSteps:[{id:'A8a1',label:'Thumbs',instructions:'Touch both thumbs',mantra:{devanagari:'\u0950 \u0905\u0902\u0917\u0941\u0937\u094d\u0920\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Om Angushthabyam Nmh',english:'Om, salutations through thumbs'}},{id:'A8a2',label:'First Fingers',instructions:'Touch both Tarjinis (first fingers)',mantra:{devanagari:'\u0928 \u0924\u0930\u094d\u091c\u0928\u0940\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Na Tarjinibyam Nmh',english:'Na, salutations through first fingers'}},{id:'A8a3',label:'Second Fingers',instructions:'Touch both Madhyamas (second fingers)',mantra:{devanagari:'\u092e \u092e\u0927\u094d\u092f\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Ma Madhymabyam Nmh',english:'Ma, salutations through middle fingers'}},{id:'A8a4',label:'Third Fingers',instructions:'Touch both Anamika (third fingers)',mantra:{devanagari:'\u0936\u093f \u0905\u0928\u093e\u092e\u093f\u0915\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Shi Anamikabyam Nmh',english:'Shi, salutations through ring fingers'}},{id:'A8a5',label:'Little Fingers',instructions:'Touch both Kanishtha (little fingers)',mantra:{devanagari:'\u0935 \u0915\u0928\u093f\u0937\u094d\u0920\u0915\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Va Kanishthakabyam Nmh',english:'Va, salutations through little fingers'}},{id:'A8a6',label:'Hand Backs',instructions:'Move front of both hands over backs of both hands',mantra:{devanagari:'\u092f \u0915\u0930\u0924\u0932\u0915\u0930 \u092a\u0943\u0937\u094d\u0920\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Ya Krtlskr Prasthabyam Nmh',english:'Ya, salutations through hands'}},{id:'A8b1',label:'Heart',instructions:'Touch heart with four fingers of both hands',mantra:{devanagari:'\u0950 \u0939\u0943\u0926\u092f\u093e\u092f\u0947 \u0928\u092e\u0903',roman:'Om Hrdyaye Nmh',english:'Om, salutations to the heart'}},{id:'A8b2',label:'Forehead',instructions:'Touch forehead',mantra:{devanagari:'\u0928 \u0936\u093f\u0930\u0938\u0947 \u0938\u094d\u0935\u093e\u0939\u093e',roman:'Na Shirse Svaha',english:'Na, offering to the head'}},{id:'A8b3',label:'Top of Head',instructions:'Touch top of head',mantra:{devanagari:'\u092e \u0936\u093f\u0916\u093e\u092f\u0947 \u0935\u0937\u094d\u091f',roman:'Ma Shikhaye Vsht',english:'Ma, to the crown'}},{id:'A8b4',label:'Shoulders',instructions:'Touch right shoulder with left hand and vice versa',mantra:{devanagari:'\u0936\u093f \u0915\u0935\u091a\u093e\u092f \u0939\u0941\u092e',roman:'Shi Kvchay Hum',english:'Shi, armor of protection'}},{id:'A8b5',label:'Eyes',instructions:'Touch both eyes with first and second fingers of right hand',mantra:{devanagari:'\u0935 \u0928\u0947\u0924\u094d\u0930\u0947\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903',roman:'Va Netrabyam Nmh',english:'Va, salutations to the eyes'}},{id:'A8b6',label:'Left Palm Strike',instructions:'Strike left palm with first and second finger of right hand',mantra:{devanagari:'\u092f \u0905\u0938\u094d\u0924\u094d\u0930\u093e\u092f \u092b\u091f',roman:'Ya Astray Phat',english:'Ya, the divine weapon'}}],mantra:{devanagari:'\u0950 \u0905\u0902\u0917\u0941\u0937\u094d\u0920\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903\u0964 \u0928 \u0924\u0930\u094d\u091c\u0928\u0940\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903\u0964 \u092e \u092e\u0927\u094d\u092f\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903\u0964 \u0936\u093f \u0905\u0928\u093e\u092e\u093f\u0915\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903\u0964 \u0935 \u0915\u0928\u093f\u0937\u094d\u0920\u0915\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903\u0964 \u092f \u0915\u0930\u0924\u0932\u0915\u0930 \u092a\u0943\u0937\u094d\u0920\u093e\u092d\u094d\u092f\u093e\u0902 \u0928\u092e\u0903\u0964',roman:'Om Angushthabyam Nmh. Na Tarjinibyam Nmh. Ma Madhymabyam Nmh. Shi Anamikabyam Nmh. Va Kanishthakabyam Nmh. Ya Krtlskr Prasthabyam Nmh.',english:'Touch each finger pair while chanting the syllables Om, Na, Ma, Shi, Va, Ya.'},duration:120},{id:'A9',number:9,title:{devanagari:'\u092d\u0942 \u0936\u0941\u0926\u094d\u0927\u093f',roman:'Bhu Shuddhi',english:'Purification of Space'},instructions:'Throw black sesame seeds (til) around the performer to keep away evil spirits.',actionDescription:'Throw black til seeds around you',mantra:{devanagari:'\u0905\u092a\u0938\u0930\u094d\u092a\u0928\u094d\u0924\u0941 \u0924\u0947 \u092d\u0942\u0924\u094b \u092f\u0947 \u092d\u0942\u0924\u093e \u092d\u0941\u0935\u093f \u0938\u0902\u0938\u094d\u0925\u093f\u0924\u093e\u0903\u0964 \u092f\u0947 \u092d\u0942\u0924\u093e \u0935\u093f\u0918\u094d\u0928 \u0915\u0930\u094d\u0924\u093e\u0930\u0938\u094d\u0924\u0947 \u0917\u091a\u094d\u091b\u0928\u094d\u0924\u0941 \u0936\u093f\u0935\u093e\u091c\u094d\u091e\u092f\u093e\u0964',roman:'Apasarpantu Te Bhuto Ye Bhuta Bhuvi Samsthitah. Ye Bhuta Vigna Kartaras Te Gacchantu Shivajnaya.',english:'Those evil spirits who are in this place and who may disturb my meditation, let them go away by the order of Lord Shiva.'},isOptional:!0,duration:30},{id:'A10',number:10,title:{devanagari:'\u092a\u094d\u0930\u093e\u0923\u093e\u092f\u093e\u092e',roman:'Pranayam',english:'Regulated Breathing'},instructions:'Inhale and exhale breath 3 times with calm disposition. This is a yogic practice for proper disposition of mind.',actionDescription:'Inhale and exhale slowly 3 times',isOptional:!1,duration:60},{id:'A11',number:11,title:{devanagari:'\u092a\u094d\u0930\u094b\u0915\u094d\u0937\u0923\u093e',roman:'Prokshana',english:'Body Purification'},instructions:'Sprinkle water on body with Vishthur from Pranipatr while reciting the mantra.',actionDescription:'Sprinkle water on yourself with Vishthur',mantra:{devanagari:'\u0924\u0940\u0930\u094d\u0925\u0947 \u0938\u094d\u0928\u0947\u092f\u0902 \u0924\u0940\u0930\u094d\u0925\u0902 \u090f\u0935 \u0938\u092e\u093e\u0928\u0902 \u092d\u0935\u0924\u093f \u092e\u0928\u0903\u0964 \u0936\u0902\u0938\u094b \u0906\u0930\u0941\u0937\u094b \u0927\u0942\u0930\u094d\u0924\u093f\u0903 \u092a\u094d\u0930\u093e\u0923\u0902 \u092e\u0930\u094d\u0924\u094d\u092f\u0938\u094d\u092f \u0930\u0915\u094d\u0937\u0923\u094b \u092c\u094d\u0930\u0939\u094d\u092e\u0923\u0938\u094d\u092a\u0924\u093f\u0964',roman:'Tirthey Sneym Tirthm Ev Smanam Bhvti Manh. Shmso Arrushho Dhurtih Prann Mrtysy Rkshano Brhmnspti.',english:'Let this water have the same effect as bathing at a holy place. Let it heal our body from sickness and save us from death.'},isOptional:!0,duration:30},{id:'A12',number:12,title:{devanagari:'\u092e\u093e\u0930\u094d\u091c\u0928',roman:'Marjana',english:'Inner Self Purification'},instructions:'Purify inner self by recitation of mantra only. No water is used.',actionDescription:'Recite mantra only (no water)',mantra:{devanagari:'\u0907\u0924\u093f \u092e\u0928\u094d\u0924\u094d\u0930 \u0938\u094d\u0928\u093e\u0928\u0940\u092f\u0902 \u0928\u092e\u0903',roman:'Iti Mnantr Snamiyni Nmh',english:'Salutations through the mantra bath.'},isOptional:!0,duration:15},{id:'A13',number:13,title:{devanagari:'\u092a\u0935\u093f\u0924\u094d\u0930\u0940 \u0927\u093e\u0930\u0923\u093e',roman:'Pavitri Dharna',english:'Wearing the Sacred Ring'},instructions:'Wear a ring made of dhurva grass (or silver/gold ring) on the anamika (ring) finger during the ritual.',actionDescription:'Place pavitri ring on ring finger',mantra:{devanagari:'\u0935\u0938\u094b\u0903 \u092a\u0935\u093f\u0924\u094d\u0930 \u0905\u0938\u093f \u0936\u0924\u0927\u093e\u0930\u0902 \u0935\u0938\u0942\u0928\u093e\u0902 \u092a\u0935\u093f\u0924\u094d\u0930 \u0905\u0938\u093f \u0938\u0939\u0938\u094d\u0930 \u0927\u093e\u0930\u0902\u0964 \u0905\u092f\u0915\u094d\u0937\u094d\u092e\u093e\u0935\u0903 \u092a\u094d\u0930\u091c\u092f\u093e \u092a\u094d\u0930\u093f\u092f\u093e \u0938\u0902\u0938\u0943\u091c\u093e\u092e\u093f \u0930\u093e\u092f\u0938\u094d\u092a\u094b\u0937\u0947\u0923 \u092c\u0939\u0941\u0932\u093e \u092d\u0935\u0928\u094d\u0924\u093f\u0964',roman:'Vsoh Pvitrm Asi Shtdharm Vsunam Pvitrm Asi Shstr Dharm. Aykshma Vh Prjya Smsrjami Rays Poshhen Bhula Bhvnti.',english:'Oh Vasus, make us pure. May this pavitri remove our hundred impurities. May we be free from all ailments and may our progeny be large and happy.'},isOptional:!1,duration:30},{id:'A14',number:14,title:{devanagari:'\u0905\u0928\u0941\u0932\u0947\u092a\u0928',roman:'Anulepna',english:'Applying Tilak'},instructions:'Apply tilak paste (chandan + saffron) to self, deep (lamp), doop (incense), Surya (sky), and others present.',actionDescription:'Apply tilak to self, lamp, incense, sky, and others',isOptional:!1,subSteps:[{id:'A14a',label:'Tilak to Self',instructions:'Apply tilak on your own forehead.',mantra:{devanagari:'\u092a\u0930\u092e\u093e\u0924\u094d\u092e\u0928\u0947 \u092a\u0941\u0930\u0941\u0937\u094b\u0924\u094d\u0924\u092e\u093e\u092f \u092a\u0902\u091a \u092d\u0942\u0924\u093e\u0924\u094d\u092e\u0915\u093e\u092f \u0935\u093f\u0936\u094d\u0935\u093e\u0924\u094d\u092e\u0928\u0947 \u092e\u0928\u094d\u0924\u094d\u0930 \u0928\u093e\u0925\u093e\u092f \u0906\u0924\u094d\u092e\u0928\u0947 \u0928\u093e\u0930\u093e\u092f\u0923\u093e\u092f \u0906\u0927\u093e\u0930 \u0936\u0915\u094d\u0924\u094d\u092f\u0948 \u0938\u092e\u093e\u0932\u092d\u0928\u0902 \u0917\u0928\u094d\u0927\u094b \u0928\u092e\u0903 \u0905\u0930\u094d\u0917\u094b \u0928\u092e\u0903 \u092a\u0941\u0937\u094d\u092a\u0902 \u0928\u092e\u0903\u0964',roman:'Parmatmne Purushhotmaye Pnch Bhutatmkay Vishvatmne Mntr Nathay Atmne Naraynay Adhar Shktyai Smalubnm Gndho Nmh Argo Nmh Pushpam Nmh.',english:'I apply tilak with reverence to Vishnu \u2014 Parmatma, Purushotama, the five-elemental soul, the universal soul.'}},{id:'A14b',label:'Tilak to Lamp (Deep)',instructions:'Apply tilak, arghya, and flowers to the lamp.',mantra:{devanagari:'\u0938\u094d\u0935 \u092a\u094d\u0930\u0915\u093e\u0936\u094b \u092e\u0939\u093e \u0926\u0940\u092a\u0903 \u0938\u0930\u094d\u0935\u0924\u0938\u094d\u0924\u093f\u092e\u093f\u0930\u093e\u092a\u0939\u0903\u0964 \u092a\u094d\u0930\u0938\u0940\u0926 \u092e\u092e \u0917\u094b\u0935\u093f\u0928\u094d\u0926 \u0926\u0940\u092a\u094b\u092f\u0902 \u092a\u0930\u093f\u0915\u0932\u094d\u092a\u093f\u0924\u093e\u0964',roman:'Sv Prakasho Mha Diph Srvtstimiraph Prasid Mm Govind Dipaym Priklpita.',english:'O Govind, you are self-luminous, a great source of light, remover of all darkness. Be pleased with me and enlighten me.'}},{id:'A14c',label:'Tilak to Incense (Doop)',instructions:'Apply tilak to agarbati/doop.',mantra:{devanagari:'\u0935\u0928\u0938\u094d\u092a\u0924\u093f \u0930\u0938\u094b \u0926\u093f\u0935\u094d\u092f\u094b \u0917\u0928\u094d\u0927\u093e\u0927\u094d\u092f \u0917\u0928\u094d\u0927\u0935\u0924\u094d \u0924\u092e\u0903\u0964 \u0906\u0927\u093e\u0930 \u0936\u0915\u094d\u0924\u094d\u092f\u0948 \u0938\u0930\u094d\u0935 \u0926\u0947\u0935\u093e\u0928\u093e\u092e\u094d \u0927\u0942\u092a\u094b \u0928\u092e\u0903 \u0905\u0930\u094d\u0917\u094b \u0928\u092e\u0903 \u092a\u0941\u0937\u094d\u092a\u0902 \u0928\u092e\u0903\u0964',roman:'Vnespati Rso Divyo Gndhadya Gndvt Tmh Adhar Sktyai Srv Devanam Dupo Nmh Argo Nmh Pushpm Nmh.',english:'May all offerings be fragrant and divine. I offer tilak to the Primordial Energy and all gods.'}},{id:'A14d',label:'Tilak to Sun & Deities',instructions:'Show tilak and arghya to sky, then put in nirmal thali.',mantra:{devanagari:'\u0928\u092e\u094b \u0927\u0930\u094d\u092e \u0928\u093f\u0927\u093e\u0928\u093e\u092f \u0928\u092e\u0903 \u0938\u094d\u0935\u0915\u0943\u0924\u0938\u093e\u0915\u094d\u0937\u0923\u0948\u0964 \u0928\u092e\u0903 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0937 \u0926\u0947\u0935\u093e\u092f \u0936\u094d\u0930\u0940 \u092d\u093e\u0938\u094d\u0915\u0930\u093e\u092f \u0928\u092e\u0903 \u0905\u0930\u094d\u0917\u094b \u0928\u092e\u0903 \u092a\u0941\u0937\u094d\u092a\u0902 \u0928\u092e\u0903 \u0917\u0928\u094d\u0927\u094b \u0928\u092e\u0903\u0964',roman:'Nm Dhrm Nidanay Nmh Svkrt-Sakshnai Nmh Prtiksh Devay Shri Baskeray Nmh Argo Nmh Pushpm Nmh Gndo Nmh.',english:'I bow to the lord of dharma, to all divinities, and to the Suns (Bhaskars).'}},{id:'A14e',label:'Tilak to Others',instructions:'Apply tilak to all present family members.',mantra:{devanagari:'\u092e\u0928\u094d\u0924\u094d\u0930\u093e\u0930\u094d\u0925\u093e \u0938\u092b\u0932\u093e \u0938\u0928\u094d\u0924\u0941 \u092a\u0942\u0930\u094d\u0923\u0903 \u0938\u0928\u094d\u0924\u0941 \u0928\u094b\u0930\u094d\u0925\u093e\u0903\u0964 \u0936\u0924\u094d\u0930\u0942\u0923\u093e\u0902 \u092c\u0941\u0926\u094d\u0927\u093f \u0928\u093e\u0936\u094b\u0938\u094d\u0924\u0941 \u092e\u093f\u0924\u094d\u0930\u093e\u0923\u093e\u092e\u094d \u0909\u0926\u092f\u0938\u094d\u0924\u0935\u0964 \u0906\u092f\u0941\u0930\u094d \u0906\u0930\u094b\u0917\u094d\u092f\u092e\u094d \u0910\u0936\u094d\u0935\u0930\u094d\u092f\u092e\u094d \u090f\u0924\u0924\u094d \u0924\u094d\u0930\u093f\u0924\u092f\u092e\u094d \u0905\u0938\u094d\u0924\u0941\u0924\u0947 \u091c\u0940\u0935 \u0924\u094d\u0935\u0902 \u0936\u0930\u0926\u0903 \u0936\u0924\u092e\u094d\u0964',roman:'Mntrartha Sflah Sntu Purnh Sntu Northah. Shtrunam Buddhi Nashstu Mitrnam Udyestv. Ayur-Arogym-Eshvrym Ett Tritym Astute Jiv Tvm Shrdh Shtm.',english:'May the mantras be effective. May your enemies lose intelligence, may friends prosper. May you have long life, health, and prosperity. Live a hundred autumns.'}}],duration:180},{id:'A15',number:15,title:{devanagari:'\u0927\u0942\u092a \u0926\u0940\u092a \u0938\u0902\u0915\u0932\u094d\u092a \u0938\u093f\u0926\u094d\u0927\u093f \u092a\u094d\u0930\u093e\u0930\u094d\u0925\u0928\u093e',roman:'Dhup Deep Sankalp Siddhi Prarthna',english:'Prayer for Success'},instructions:'Pour water from Pranipatr with Vishthur and arghya from left hand onto fingers of right hand over nirmal pot.',actionDescription:'Pour water through hands over nirmal pot',mantra:{devanagari:'\u092f\u0924\u094d\u0930\u093e\u0938\u094d\u0924\u093f \u092e\u093e\u0924\u093e \u0928 \u092a\u093f\u0924\u093e \u0928 \u092c\u0928\u094d\u0927\u0941\u0903 \u092d\u094d\u0930\u093e\u0924\u093e\u092a\u093f \u0928 \u092f\u0924\u094d\u0930 \u0938\u0941\u0939\u0943\u0924\u094d \u091c\u0928\u0936\u094d\u091a \u0928 \u091c\u094d\u091e\u093e\u092f\u0924\u0947\u0964 \u092f\u0924\u094d\u0930 \u0926\u093f\u0928\u0902 \u0928 \u0930\u093e\u0924\u094d\u0930\u0902 \u0924\u0924\u094d\u0930\u093e\u0924\u094d\u092e \u0926\u0940\u092a\u0902 \u0936\u0930\u0923\u0902 \u092a\u094d\u0930\u092a\u0939\u094d\u092f\u0947\u0964 \u0906\u0924\u094d\u092e\u0928\u0947 \u0928\u093e\u0930\u093e\u092f\u0923\u093e\u092f \u0906\u0927\u093e\u0930 \u0936\u0915\u094d\u0924\u094d\u092f\u0948 \u0926\u0940\u092a \u0927\u0942\u092a \u0938\u0902\u0915\u0932\u094d\u092a\u093e\u0924\u094d \u0938\u093f\u0926\u094d\u0927\u093f\u0930\u094d \u0905\u0938\u094d\u0924\u0941\u0964 \u0926\u0940\u092a\u094b \u0928\u092e\u0903 \u0927\u0942\u092a\u094b \u0928\u092e\u0903\u0964',roman:'Ytrasti Mata Na Pita Nm Bnduh Bratapi Na Ytr Suht Jnsh Ch Na Jnayte. Ytr Dinm Na Ratre Ttratvm Dipm Shrnm Prphye. Atmne Naraynay Adhar Shktyai Dip Dup Snklpat Siddhir Astu. Dipo Nmh Dhupo Nmh.',english:'When I am deep in meditation, unaware of father, mother, brother or friend, day or night \u2014 I take refuge under the luminous light of Narayana, the Primordial Energy. May this Doop Deep Puja resolution be propitious.'},isOptional:!0,duration:60}]},{id:'B',title:{devanagari:'\u092e\u0927\u094d\u092f\u092e \u092d\u093e\u0917',roman:'Madhyam Bhaga',english:'Main Birthday Puja'},subtitle:'Birthday-specific puja invoking 7 Devreshis through Nariwan with 7 knots.',steps:[{id:'B0',number:0,title:{devanagari:'\u0927\u094d\u092f\u093e\u0928 (\u0935\u093f\u0937\u094d\u0923\u0941)',roman:'Dhyan (Vishnu)',english:'Meditation on Lord Vishnu'},instructions:'Before starting Madhyam Bhaga, meditate on Lord Vishnu. Place the Nariwan (with 7 knots representing 7 Devreshis) on a raised object in a thali.',actionDescription:'Place Nariwan elevated in thali, meditate',mantra:{devanagari:'\u0936\u093e\u0928\u094d\u0924\u093e\u0915\u093e\u0930\u0902 \u092d\u0941\u091c\u0917 \u0936\u092f\u0928\u0902 \u092a\u0926\u094d\u092e\u0928\u093e\u092d\u0902 \u0938\u0941\u0930\u0947\u0936\u0902\u0964 \u0935\u093f\u0936\u094d\u0935\u093e\u0927\u093e\u0930\u0902 \u0917\u0917\u0928\u0938\u0926\u0943\u0936\u094d\u092f\u0902 \u092e\u0947\u0918\u0935\u0930\u094d\u0923\u0902 \u0936\u0941\u092d\u093e\u0919\u094d\u0917\u092e\u094d\u0964 \u0932\u0915\u094d\u0937\u094d\u092e\u0940 \u0915\u093e\u0928\u094d\u0924\u0902 \u0915\u092e\u0932\u0928\u092f\u0928\u0902 \u092f\u094b\u0917\u092c\u093f\u0930\u094d\u0927\u094d\u092f\u093e\u0928 \u0917\u092e\u094d\u092f\u0902\u0964 \u0935\u0928\u094d\u0926\u0947 \u0935\u093f\u0937\u094d\u0923\u0941\u0902 \u092d\u0935\u092d\u092f\u0939\u0930\u0902 \u0938\u0930\u094d\u0935\u0932\u094b\u0915\u0948\u0915\u0928\u093e\u0925\u092e\u094d\u0964',roman:'Shanta Kaarm Bhujeg Shaynam Padam Nabham Suresham. Wishwadaram Gagan Sadreshyam Meghvarnam Shulbhangam. Lakhshimi Kantam Kamal Naynam Yogbir Dyan Gameyam. Vandey Veshnum Bhaw Bhaye Haram Sarw Lokaiyk Natham.',english:'I bow to Lord Vishnu, who sits calmly on Sheshnag, who has lotus at His navel, lord of devas, support of the universe, present everywhere like sky, beautiful like clouds, husband of Lakshmi, lotus-eyed, realized through meditation, who removes all fears, lord of all lords.'},isOptional:!1,duration:60},{id:'B1',number:1,title:{devanagari:'\u0906\u0935\u093e\u0939\u0928 \u090f\u0935\u0902 \u0905\u0930\u094d\u091a\u093e\u092e',roman:'Avahan & Archam',english:'Welcoming the Seven Rishis'},instructions:'Welcome the 7 Devreshis to take their seats and seek permission to offer worship.',actionDescription:'Invite the 7 Devreshis',mantra:{devanagari:'\u0906\u0935\u093e\u0939\u093f \u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u2014 \u0905\u0936\u094d\u0935\u0924\u094d\u0925\u093e\u0928\u0928\u0947, \u092c\u0932\u092f\u0947, \u0935\u094d\u092f\u093e\u0938\u093e\u092f, \u0939\u0928\u0941\u092e\u0924\u0947, \u0915\u0943\u092a\u093e\u091a\u093e\u0930\u094d\u092f\u093e\u092f, \u092e\u093e\u0930\u094d\u0915\u0923\u094d\u0921\u0947\u092f\u093e\u092f, \u092a\u0930\u0936\u0941\u0930\u093e\u092e\u093e\u092f\u0964 \u092d\u0915\u094d\u0924\u093e\u0928\u0941\u0917\u094d\u0930\u0939 \u0915\u093e\u0930\u0915 \u0905\u0938\u094d\u092e\u0924\u094d \u0926\u092f\u093e\u0928\u0941\u0930\u094b\u0927\u0947\u0928 \u0938\u0928\u094d\u0928\u093f\u0927\u093e\u0928\u0902 \u0915\u0941\u0930\u0941 \u092a\u094d\u0930\u092d\u0941\u0964 \u0905\u0930\u094d\u091a\u093e\u092e\u093f \u0928\u092e\u0903\u0964',roman:'Avahi Spt Janmotsv Devtabhyh \u2014 Asvathanane, Blye, Vyasay, Hanumte, Krpacharyay, Markndeyay, Prshuramay. Bhktanugrh Kark Asmat Dyanurdhen Snnidhanum Kuru Prbhu. Archami Nmh.',english:'Oh Devreshis (Ashwatthama, Bali, Vyasa, Hanuman, Kripacharya, Markandeya, Parashurama) \u2014 you who bless devotees with divine grace, please be present here and permit us to offer prayers.'},isOptional:!1,duration:60},{id:'B2',number:2,title:{devanagari:'\u092a\u094d\u0930\u093e\u0923 \u092a\u094d\u0930\u0924\u093f\u0937\u094d\u0920\u093e',roman:'Pran Pratishtha',english:'Bringing Idols to Life'},instructions:'Place water in panchpatra with vishthur or darbha. Recite three prayers, put flower petals in cup after each. Then sprinkle water on Nariwan.',actionDescription:'Sprinkle water on Nariwan to bring it to life',mantra:{devanagari:'\u0938\u092e\u0935\u0903 \u0938\u0943\u091c\u093e\u092e\u093f \u0939\u0943\u0926\u092f\u0902 \u0938\u0902\u0938\u0943\u0937\u094d\u091f \u092e\u0928\u094b\u0905\u0938\u094d\u0924\u0941 \u0935\u0903\u0964 \u0938\u0902\u0903 \u0938\u0943\u0937\u094d\u091f\u0938\u094d\u0924\u0928\u094d\u0935\u0903 \u0938\u0928\u094d\u0924\u0941 \u0935\u0903 \u0938\u0902 \u0938\u0943\u0937\u094d\u091f\u0903\u0964 \u092a\u094d\u0930\u0923\u094b \u0905\u0938\u094d\u0924\u0941 \u0935\u0903 \u0938\u0902\u092f\u093e\u0935\u0903 \u092a\u094d\u0930\u093f\u092f\u093e\u0903 \u0924\u0928\u094d\u0935\u0903\u0964 \u0938\u0902 \u092a\u094d\u0930\u093f\u092f\u093e\u0903 \u0939\u0943\u0926\u092f\u093e\u0928\u093f \u0935\u0903\u0964 \u0906\u0924\u094d\u092e\u093e \u0935\u094b \u0905\u0938\u094d\u0924\u0941 \u0938\u0902 \u092a\u094d\u0930\u093f\u092f\u0903 \u0938\u0902 \u092a\u094d\u0930\u093f\u092f\u0903 \u0924\u0928\u094d\u0935\u094b\u092e\u092e\u094d\u0964',roman:'Smvh Srjami Hrdym Smsrshht Mnoastu Vh. Smh Srshtastnvh Sntu Vh Sm Srshhth. Prano Astu Vh Smyavh Priyh Tnvh. Sm Priyh Hrdyani Vh. Atma Vo Astu Sm Priya Sm Priyh Tnvomm.',english:'I place you in my heart for continued union with my mind and prana. You are the Atma residing in my body, please continue to stay with me.'},subSteps:[{id:'B2a',label:'Prayer to the Lord (3 recitations + flowers)',instructions:'Recite this prayer three times. After each recitation, put a few flower petals into the panchpatra cup.',mantra:{devanagari:'\u0938\u092e\u0935\u0903 \u0938\u0943\u091c\u093e\u092e\u093f \u0939\u0943\u0926\u092f\u0902 \u0938\u0902\u0938\u0943\u0937\u094d\u091f \u092e\u0928\u094b\u0905\u0938\u094d\u0924\u0941 \u0935\u0903\u0964 \u0938\u0902\u0903 \u0938\u0943\u0937\u094d\u091f\u0938\u094d\u0924\u0928\u094d\u0935\u0903 \u0938\u0928\u094d\u0924\u0941 \u0935\u0903 \u0938\u0902 \u0938\u0943\u0937\u094d\u091f\u0903\u0964 \u092a\u094d\u0930\u0923\u094b \u0905\u0938\u094d\u0924\u0941 \u0935\u0903 \u0938\u0902\u092f\u093e\u0935\u0903 \u092a\u094d\u0930\u093f\u092f\u093e\u0903 \u0924\u0928\u094d\u0935\u0903\u0964 \u0938\u0902 \u092a\u094d\u0930\u093f\u092f\u093e\u0903 \u0939\u0943\u0926\u092f\u093e\u0928\u093f \u0935\u0903\u0964 \u0906\u0924\u094d\u092e\u093e \u0935\u094b \u0905\u0938\u094d\u0924\u0941 \u0938\u0902 \u092a\u094d\u0930\u093f\u092f\u0903 \u0938\u0902 \u092a\u094d\u0930\u093f\u092f\u0903 \u0924\u0928\u094d\u0935\u094b\u092e\u092e\u094d\u0964',roman:'Smvh Srjami Hrdym Smsrshht Mnoastu Vh. Smh Srshtastnvh Sntu Vh Sm Srshhth. Prano Astu Vh Smyavh Priyh Tnvh. Sm Priyh Hrdyani Vh. Atma Vo Astu Sm Priya Sm Priyh Tnvomm.',english:'I place you in my heart for continued union with my mind and prana. You are the soul residing in my body, please stay with me.'}},{id:'B2b',label:'Bringing Devreshis to Life',instructions:'Sprinkle water over the Nariwan with Vishthur or darbha to bring the Devreshis to life.',mantra:{devanagari:'\u0905\u0936\u094d\u0935\u093f\u0928\u094b\u0903 \u092a\u094d\u0930\u093e\u0923\u0938\u094d\u0924\u094c \u0924\u0947 \u092a\u094d\u0930\u093e\u0923 \u0926\u0924\u094d\u0924\u093e\u0902 \u0924\u0947\u0928 \u091c\u0940\u0935\u0964 \u092e\u093f\u0924\u094d\u0930\u093e\u0935\u0930\u0941\u0923\u094d\u092f\u094b\u0903 \u092a\u094d\u0930\u093e\u0923\u0938\u094d\u0924\u094c \u0924\u0947 \u092a\u094d\u0930\u093e\u0923 \u0926\u0924\u094d\u0924\u093e\u0902 \u0924\u0947\u0928 \u091c\u0940\u0935\u0964 \u092c\u0943\u0939\u0938\u094d\u092a\u0924\u0947\u0903 \u092a\u094d\u0930\u093e\u0923\u0938\u094d\u0924\u094c \u0924\u0947 \u092a\u094d\u0930\u093e\u0923 \u0926\u0924\u094d\u0924\u093e\u0902 \u0924\u0947\u0928 \u091c\u0940\u0935\u0964',roman:'Ashivnoh Pranstau Te Pranm Dttan Ten Jiv. Mitravarunyoh Pranstau Te Pran Dttan Ten Jiv. Brhspteh Pranstau Te Pran Dttan Ten Jiv.',english:'A request to Ashwatthama, Brahaspati, Mitra, and Varuna to please bring to life all the Devreshis.'}},{id:'B2c',label:'Naming the Seven Devreshis',instructions:'Conclude by naming each of the seven Devreshis and declaring them alive to receive oblations.',mantra:{devanagari:'\u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u2014 \u0905\u0936\u094d\u0935\u0924\u094d\u0925\u093e\u0928\u0928\u0947, \u092c\u0932\u092f\u0947, \u0935\u094d\u092f\u093e\u0938\u093e\u092f, \u0939\u0928\u0941\u092e\u0924\u0947, \u0915\u0943\u092a\u093e\u091a\u093e\u0930\u094d\u092f\u093e\u092f, \u092e\u093e\u0930\u094d\u0915\u0923\u094d\u0921\u0947\u092f\u093e\u092f, \u092a\u0930\u0936\u0941\u0930\u093e\u092e\u093e\u092f \u2014 \u091c\u0940\u0935\u0927\u0928\u0902 \u092a\u0930\u093f\u0915\u0932\u094d\u092a\u092f\u093e\u092e\u093f \u0928\u092e\u0903\u0964',roman:'Spt Jnmotsv Devtabhyh \u2014 Asvathanane, Blye, Vyasay, Hanumte, Krpacharyay, Markndeyay, Prshuramay \u2014 Jivdhanm Pariklpyami Nmh.',english:'I declare the seven Devreshis \u2014 Ashwatthama, Bali, Vyasa, Hanuman, Kripacharya, Markandeya, Parashurama \u2014 alive and ready to receive worship.'}}],isOptional:!1,duration:90},{id:'B3',number:3,title:{devanagari:'\u092a\u093e\u0926\u094d\u092f',roman:'Padya',english:'Washing Deities Feet'},instructions:'Purify water with Apo Prashana mantra (3 times). Then wash deity feet by sprinkling Panchamrit water on Nariwan.',actionDescription:'Sprinkle sanctified water on Nariwan',mantra:{devanagari:'\u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u2014 \u0917\u0902\u0917\u093e\u0926\u093f \u0938\u0930\u094d\u0935 \u0924\u0940\u0930\u094d\u0925\u092d\u094d\u092f \u0906\u0928\u0940\u0924\u0902 \u0924\u094b\u092f\u092e\u0941\u0924\u094d\u0924\u092e\u092e\u094d\u0964 \u092a\u093e\u0927\u093e\u0930\u094d\u0925\u0902 \u0938\u092e\u094d\u092a\u094d\u0930\u0926\u093e\u0938\u094d\u092f\u093e\u092e\u093f \u0917\u0943\u0939\u0928\u094d\u0924\u0941\u0964',roman:'Spt Jnmotsv Devtabhyh \u2014 Gngadi Srv Tirtha byo Anitm Toym Uttmm. Padhartham Samarpayami Granantu.',english:'Oh Devreshis, I use this sacred water from Ganges and holy rivers for washing your feet. Please accept it.'},isOptional:!1,duration:60},{id:'B4',number:4,title:{devanagari:'\u0905\u0930\u094d\u0918\u094d\u092f\u092e\u094d',roman:'Arghyam',english:'Washing Hands & Face'},instructions:'Add 8 Ashtang ingredients (water, milk, curd, ghee, rice, barley, sarshap, vishthur) to water. Pour over Nariwan.',actionDescription:'Pour Ashtang water over Nariwan',mantra:{devanagari:'\u0917\u0928\u094d\u0927 \u092a\u0941\u0937\u094d\u092a \u0905\u0915\u094d\u0937\u0924\u0948\u0930\u094d\u092f\u0941\u0915\u094d\u0924\u0902 \u0905\u0930\u094d\u0927\u094d\u092f\u0902 \u0938\u092e\u094d\u092a\u093e\u0926\u093f\u0924\u0902 \u092e\u092f\u093e\u0964 \u0917\u0943\u0939\u094d\u0923\u0928\u094d\u0924\u0941 \u0905\u0930\u094d\u0927\u094d\u092f\u0902 \u092a\u094d\u0930\u0938\u0928\u094d\u0928\u093e\u0936\u094d\u091a \u092d\u0935\u0928\u094d\u0924\u0941 \u092e\u0947 \u0938\u0930\u094d\u0935\u0926\u093e\u0964 \u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u0905\u0930\u094d\u0917\u094d\u092f\u0902 \u0938\u092e\u0930\u094d\u092a\u092f\u093e\u092e\u093f \u0928\u092e\u0903\u0964',roman:'Gnd Pushpakshtlair Yuktm Gryni Sampaditm Mya. Grhnntv Argym Prasanashch Bhvntu Me Srvda. Spt Jnmotsv Devtabhyh Argyam Samarpiyamey Nmh.',english:'Oh Devreshis, please accept offerings of tilak, flowers, and akshat along with other ingredients. Please be happy with me always.'},isOptional:!1,duration:45},{id:'B5',number:5,title:{devanagari:'\u0926\u0947\u0935 \u0906\u091a\u092e\u0928',roman:'Dev Aachman',english:'Deity Purification'},instructions:'Pour pure water over deity to purify it of any materials used in oblations. Add camphor or scents.',actionDescription:'Pour scented water over Nariwan',mantra:{devanagari:'\u0915\u0930\u094d\u092a\u0942\u0930\u0947\u0923 \u0938\u0941\u0918\u0928\u094d\u0927\u0947\u0928 \u0935\u093e\u0938\u093f\u0924\u0902 \u0938\u094d\u0935\u093e\u0926 \u0936\u0940\u0924\u0932\u0902 \u0924\u094b\u092f\u0902 \u0906\u091a\u092e\u0928\u0940\u092f\u093e\u0930\u094d\u0925\u0902 \u0917\u0943\u0939\u0923\u0928\u094d\u0924\u0941 \u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903\u0964',roman:'Krpuren Sughndhn Vasitm Svad Shitlm Toym Achmanyrthm Grhnuntu Spt Janmotsv Devtabhyh.',english:'Oh Devreshis, please accept this purification with cold, tasty water scented with camphor.'},isOptional:!1,duration:30},{id:'B6',number:6,title:{devanagari:'\u0926\u0947\u0935 \u0938\u094d\u0928\u093e\u0928 / \u0905\u092d\u093f\u0937\u0947\u0915',roman:'Dev Snan / Abhishek',english:'Bathing the Deity'},instructions:'Bathe the Nariwan with Panchdashang \u2014 15 ingredients (water, milk, curd, ghee, honey, sugar, sarshap, laja, sarvaushadi, chandan/saffron, gold/silver, jewel, flowers, vashthur).',actionDescription:'Pour 15 ingredients over Nariwan',mantra:{devanagari:'\u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u2014 \u092a\u091e\u094d\u091a\u0926\u0936 \u0938\u094d\u0928\u093e\u0928\u0902 \u0938\u092e\u0930\u094d\u092a\u092f\u093e\u092e\u093f \u0928\u092e\u0903\u0964',roman:'Spt Jnmotsv Devtabhyh \u2014 Panchdash Snanum Samarpayami Nmh.',english:'Oh Devreshis, I offer the bathing ritual with 15 sacred ingredients. Please accept.'},isOptional:!1,duration:120},{id:'B7',number:7,title:{devanagari:'\u0935\u0938\u094d\u0924\u094d\u0930 \u0917\u094d\u0930\u0939\u0923',roman:'Vastra Grhan',english:'Offering Clothes'},instructions:'Offer clothes to the deity after the bath.',actionDescription:'Place cloth on Nariwan',mantra:{devanagari:'\u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u0935\u0938\u094d\u0924\u094d\u0930\u0902 \u0938\u092e\u0930\u094d\u092a\u092f\u093e\u092e\u093f \u0928\u092e\u0903\u0964',roman:'Spt Jnmotsv Devtabhyh Vstrm Samarpyami Nmh.',english:'Please accept clothes with my full reverence.'},isOptional:!1,duration:20},{id:'B8',number:8,title:{devanagari:'\u0926\u0947\u0935 \u0905\u0928\u0941\u0932\u0947\u092a\u0928',roman:'Dev Anulepna',english:'Applying Tilak to Deity'},instructions:'Apply tilak to the Nariwan seven times while reciting.',actionDescription:'Apply tilak to Nariwan 7 times',mantra:{devanagari:'\u0938\u0930\u094d\u0935\u0947\u0936\u094d\u0935\u0930 \u091c\u0917\u0924\u094d \u0935\u0928\u094d\u0926\u094d\u092f \u0926\u093f\u0935\u094d\u092f\u093e\u0938\u0928 \u0938\u0941\u0938\u0902\u0938\u094d\u0925\u093f\u0924\u0964 \u0917\u0928\u094d\u0927 \u0917\u0943\u0939\u093e\u0923 \u0926\u0947\u0935\u0947\u0936 \u0926\u093f\u0935\u094d\u092f\u0917\u0928\u094d\u0927\u094b\u092a \u0936\u094b\u092d\u093f\u0924\u092e\u094d\u0964 \u0938\u092a\u094d\u0924 \u091c\u0928\u094d\u092e\u094b\u0924\u094d\u0938\u0935 \u0926\u0947\u0935\u0924\u093e\u092d\u094d\u092f\u0903 \u0938\u092e\u093e\u0932\u092d\u0928\u0947 \u0917\u0928\u094d\u0927\u094b \u0928\u092e\u0903\u0964',roman:'Srveshvr Jgt Vindya Divyasnm Susmsthita. Gndh Grhan Devesh Divgndop Shobitm. Spt Janam Devtabyo Smalbnm Gndo Nmh.',english:'Almighty Rishis, seated on your divine seat, please accept this tilak for your beautification.'},isOptional:!1,duration:45},{id:'B9',number:9,title:{devanagari:'\u091a\u093e\u092e\u0930 / \u0906\u0930\u0924\u0940',roman:'Chamer / Arti',english:'Arti - Vishnu Stuti'},instructions:'Move Ratandeep and Doop held in a thali in front of Nariwan. Recite the six verses of Vishnu Stuti. Each verse ends with the refrain "Ghorm Hr Mm..."',actionDescription:'Wave lamp before Nariwan, recite Vishnu Stuti',mantra:{devanagari:'\u091c\u092f \u0928\u093e\u0930\u093e\u092f\u0923 \u091c\u092f \u092a\u0941\u0930\u0941\u0937\u094b\u0924\u094d\u0924\u092e \u091c\u092f \u0935\u093e\u092e\u0928 \u0915\u0902\u0938\u093e\u0930\u0947\u0964 \u0909\u0926\u094d\u0927\u0930 \u092e\u093e\u092e \u0938\u0941\u0930\u0947\u0936 \u0935\u093f\u0928\u093e\u0936\u093f\u0928\u094d \u092a\u0924\u093f\u0924\u094b\u0939\u0902 \u0938\u0902\u0938\u093e\u0930\u0947\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e \u0928\u0930\u0915 \u0930\u093f\u092a\u094b \u0915\u0947\u0936\u0935 \u0915\u0932\u094d\u092e\u0937\u092d\u093e\u0930\u0902\u0964 \u092e\u093e\u092e \u0905\u0928\u0941\u0915\u092e\u094d\u092a\u092f \u0926\u0940\u0928\u092e\u094d \u0905\u0928\u093e\u0925\u0902 \u0915\u0941\u0930\u0941 \u092d\u0935 \u0938\u093e\u0917\u0930 \u092a\u093e\u0930\u092e\u094d\u0964',roman:'Jy Narayn Jy Purushottm Jy Vamn Knsare. Uddhr Mam Suresh Vinashin Ptitohm Snsare. Ghorm Hr Mm Nrk Ripo Keshv Klmshbharm. Mam Anukmpy Dinm Anathm Kuru Bhv Sagr Parm.',english:'Victory to Narayana, Purushotama, Vamana! O Lord, destroyer of demons, I am drowning in this world \u2014 lift me up. O Keshava, enemy of those who drag people to hell, forgive my sins. Have mercy on me and take me across the ocean of worldly existence.'},subSteps:[{id:'B9v1',label:'Verse 1 - Jy Narayn',instructions:'Wave lamp and recite first verse.',mantra:{devanagari:'\u091c\u092f \u0928\u093e\u0930\u093e\u092f\u0923 \u091c\u092f \u092a\u0941\u0930\u0941\u0937\u094b\u0924\u094d\u0924\u092e \u091c\u092f \u0935\u093e\u092e\u0928 \u0915\u0902\u0938\u093e\u0930\u0947\u0964 \u0909\u0926\u094d\u0927\u0930 \u092e\u093e\u092e \u0938\u0941\u0930\u0947\u0936 \u0935\u093f\u0928\u093e\u0936\u093f\u0928\u094d \u092a\u0924\u093f\u0924\u094b\u0939\u0902 \u0938\u0902\u0938\u093e\u0930\u0947\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e \u0928\u0930\u0915 \u0930\u093f\u092a\u094b \u0915\u0947\u0936\u0935 \u0915\u0932\u094d\u092e\u0937\u092d\u093e\u0930\u0902\u0964 \u092e\u093e\u092e \u0905\u0928\u0941\u0915\u092e\u094d\u092a\u092f \u0926\u0940\u0928\u092e\u094d \u0905\u0928\u093e\u0925\u0902 \u0915\u0941\u0930\u0941 \u092d\u0935 \u0938\u093e\u0917\u0930 \u092a\u093e\u0930\u092e\u094d\u0964',roman:'Jy Narayn Jy Purushottm Jy Vamn Knsare. Uddhr Mam Suresh Vinashin Ptitohm Snsare. Ghorm Hr Mm Nrk Ripo Keshv Klmshbharm. Mam Anukmpy Dinm Anathm Kuru Bhv Sagr Parm.',english:'Victory to Narayana! O Lord, take me out of this cycle of life and death.'}},{id:'B9v2',label:'Verse 2 - Jy Jy Dev',instructions:'Continue waving lamp.',mantra:{devanagari:'\u091c\u092f \u091c\u092f \u0926\u0947\u0935 \u091c\u092f\u093e \u0938\u0941\u0930\u0938\u0942\u0926\u0928 \u091c\u092f \u0915\u0947\u0936\u0935 \u091c\u092f \u0935\u093f\u0937\u094d\u0923\u094b\u0964 \u091c\u092f \u0932\u0915\u094d\u0937\u094d\u092e\u0940\u092e\u0941\u0916 \u0915\u092e\u0932 \u092e\u0927\u0941\u0935\u094d\u0930\u0924 \u091c\u092f \u0926\u0936\u0915\u0928\u094d\u0927\u0930 \u091c\u093f\u0937\u094d\u0923\u094b\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e...',roman:'Jy Jy Dev Jya Sursudn Jy Keshv Jy Vishnu. Jy Lkshmi Mukh Kml Mdhuvrt Jy Dshkndhr Jishno. Ghorm Hr Mm...',english:'Victory to the slayer of demons, to Keshava, to Vishnu, spouse of Lakshmi, who as Rama slew Ravana.'}},{id:'B9v3',label:'Verse 3 - Ydypi Sklm',instructions:'Continue waving lamp.',mantra:{devanagari:'\u092f\u0926\u094d\u092f\u092a\u093f \u0938\u0915\u0932\u0902 \u0905\u0939\u0902 \u0915\u0932\u092f\u093e\u092e\u093f \u0939\u0930\u0947 \u0928\u0939\u093f \u0915\u093f\u092e\u094d \u0905\u092a\u093f \u0938 \u0938\u0924\u094d\u0935\u092e\u094d\u0964 \u0924\u0924\u094d \u0905\u092a\u093f \u0928 \u092e\u0941\u091e\u094d\u091a\u0924\u093f \u092e\u093e\u092e\u094d \u0907\u0926\u092e\u094d \u0905\u091a\u094d\u092f\u0941\u0924 \u092a\u0941\u0924\u094d\u0930\u0915\u0932\u0924\u094d\u0930 \u092e\u092e\u0924\u094d\u0935\u092e\u094d\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e...',roman:'Ydypi Sklm Ahm Klyami Hre Nhi Kim Api S Stvm. Tt Api N Munchti Mam Idm Achyut Putrkltr Mmtvm. Ghorm Hr Mm...',english:'O Hari, even when I know nothing is permanent, I cannot free myself from attachment to wife and sons.'}},{id:'B9v4',label:'Verse 4 - Punr Api',instructions:'Continue waving lamp.',mantra:{devanagari:'\u092a\u0941\u0928\u0930\u094d \u0905\u092a\u093f \u091c\u0928\u0928 \u092a\u0941\u0928\u0930 \u0905\u092a\u093f \u092e\u0930\u0923 \u092a\u0941\u0928\u0930 \u0905\u092a\u093f \u0917\u0930\u094d\u092d \u0928\u093f\u0935\u093e\u0938\u092e\u094d\u0964 \u0938\u094b\u0922\u0941\u092e\u094d \u0905\u0932\u0902 \u092a\u0941\u0928\u0930 \u0905\u0938\u094d\u092e\u093f\u0928\u094d \u092e\u093e\u0927\u0935 \u092e\u093e\u092e\u094d \u0909\u0926\u094d\u0927\u0930 \u0928\u093f\u091c\u0926\u093e\u0938\u092e\u094d\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e...',roman:'Punr Api Jnmm Punr Api Mrnm Punr Api Grbh Nivasm. Sodum Alm Punr Asmin Madhu Mam Uddhr Nijdasm. Ghorm Hr Mm...',english:'O Madhava, I have gone through the cycle of birth, death, and womb again and again. I can bear it no longer. Please liberate your servant.'}},{id:'B9v5',label:'Verse 5 - Tvm Jnni',instructions:'Continue waving lamp.',mantra:{devanagari:'\u0924\u094d\u0935\u0902 \u091c\u0928\u0928\u0940 \u091c\u0928\u0915\u0903 \u092a\u094d\u0930\u092d\u0941\u0930 \u0905\u091a\u094d\u092f\u0941\u0924 \u0924\u094d\u0935\u0902 \u0938\u0941\u0939\u0943\u0924\u094d \u0915\u0941\u0932\u092e\u093f\u0924\u094d\u0930\u092e\u094d\u0964 \u0924\u094d\u0935\u0902 \u0936\u0930\u0923\u0902 \u0936\u0930\u0923\u093e \u0917\u0924\u0935\u0924\u094d\u0938\u0932 \u0924\u094d\u0935\u0902 \u092d\u0935 \u091c\u0932\u0927\u093f \u0935\u0939\u093f\u0924\u094d\u0930\u092e\u094d\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e...',roman:'Tvm Jnni Jnkh Prbhur Achyut Tvm Suhrt Kulmitrm. Tvm Shrnm Shrna Gt Vtsl Tvm Bhv Jldhi Vhitrm. Ghorm Hr Mm...',english:'O Achyut, You are my Mother, Father, Friend. You provide refuge to those who surrender. You enable crossing the ocean of samsara.'}},{id:'B9v6',label:'Verse 6 - Jnk Suta',instructions:'Final verse, conclude the arti.',mantra:{devanagari:'\u091c\u093e\u0928\u0915 \u0938\u0941\u0924\u093e \u092a\u0924\u093f \u091a\u0930\u0923 \u092a\u093e\u0930\u093e\u092f\u0923 \u0936\u0902\u0915\u0930 \u092e\u0941\u0928\u093f\u0935\u0930 \u0917\u0940\u0924\u0902\u0964 \u0927\u093e\u0930\u092f \u092e\u0928\u0938\u093f \u0915\u0943\u0937\u094d\u0923 \u092a\u0941\u0930\u0941\u0937\u094b\u0924\u094d\u0924\u092e \u0935\u093e\u0930\u092f \u0938\u0902\u0938\u0943\u0924\u093f \u092d\u0940\u0924\u093f\u092e\u094d\u0964 \u0918\u094b\u0930\u0902 \u0939\u0930 \u092e\u092e...',roman:'Jnk Suta Pti Chrn Prayn Shnkr Munivr Gitm. Dhary Mnsi Krishn Purushottm Vaary Smsrti Bhitim. Ghorm Hr Mm...',english:'O Krishna, O Purushotama, hear the hymn recited by Shankara and seers at Rama\'s feet. Please remove all fear from me.'}}],isOptional:!1,duration:300},{id:'B10',number:10,title:{devanagari:'\u092a\u094d\u0930\u0947\u092a\u094d\u092f\u0941\u0928 / \u0928\u0948\u0935\u0947\u0926\u094d\u092f\u092e\u094d',roman:'Prepyun / Naivedyam',english:'Offering Food (Bhog)'},instructions:'Place Te\'hr in front of deity. Remove Chattu (250g) in separate plate. Make 7 handfuls as Dev-Bhog. All present touch the Prasad plate (or form a chain). Recite invoking all deities.',actionDescription:'Offer Te\'hr to all deities',mantra:{devanagari:'\u0905\u092e\u0943\u0924\u0947\u0936 \u092e\u0941\u0926\u094d\u0930\u092f\u093e \u0905\u092e\u0943\u0924\u0940\u0915\u0943\u0924\u094d\u092f \u0905\u092e\u0943\u0924\u092e\u094d \u0905\u0938\u094d\u0924\u0941 \u0905\u092e\u0943\u0924\u093e\u092f\u0924\u093e\u0902 \u0928\u0948\u0935\u0947\u0926\u094d\u092f\u092e\u094d\u0964 \u0938\u093e\u0935\u093f\u0924\u094d\u0930\u093e\u0923\u093f \u0938\u093e\u0935\u093f\u0924\u094d\u0930\u0938\u094d\u092f \u0926\u0947\u0935\u0938\u094d\u092f \u0924\u094d\u0935\u093e \u0938\u0935\u093f\u0924\u0941\u0903 \u092a\u094d\u0930\u0938\u094d\u0935\u0947 \u0936\u093f\u0935\u0928\u094b\u0930\u094d \u092c\u093e\u0939\u0941\u092d\u094d\u092f\u093e\u0902 \u092a\u0942\u0937\u094d\u0923\u094b \u0939\u0938\u094d\u0924\u093e\u092d\u094d\u092f\u093e\u092e\u094d\u0964',roman:'Amrtesh Mudrya Amrtikrty Amrtm Astu Amrtaytam Naivedym. Savitrani Savitrsy Devsy Tva Svituh Prsve Shivnor Bahubhyam Pushno Hstbhyam.',english:'Let this offering be like amrit (nectar of immortality). It has been prepared by the hard labor of our arms and hands.'},isOptional:!1,duration:300}]},{id:'C',title:{devanagari:'\u0905\u0928\u094d\u0924\u093f\u092e \u092d\u093e\u0917 / \u0915\u094d\u0937\u092e\u093e \u092f\u093e\u091a\u0928\u093e',roman:'Antim Bhaga / Kshma Yachna',english:'Closing Prayer & Nariwan Tying'},subtitle:'Concluding prayer and tying the sacred thread.',steps:[{id:'C1',number:1,title:{devanagari:'\u0915\u094d\u0937\u092e\u093e \u092f\u093e\u091a\u0928\u093e',roman:'Kshma Yachna',english:'Closing Prayer'},instructions:'With folded hands, recite the closing prayer asking for divine protection.',actionDescription:'Fold hands and recite closing prayer',mantra:{devanagari:'\u0906\u092a\u0928\u094d\u0928\u094b\u0938\u094d\u092e\u093f \u0936\u0930\u0923\u094d\u092f\u094b\u0938\u094d\u092e\u093f \u0938\u0930\u094d\u0935\u093e\u0935\u0938\u094d\u0925\u093e\u0938\u0941 \u0938\u0930\u094d\u0935\u0926\u093e\u0964 \u092d\u0917\u0935\u0928\u094d \u0924\u094d\u0935\u0902 \u092a\u094d\u0930\u092a\u0928\u094d\u0928\u094b\u0938\u094d\u092e\u093f \u0930\u0915\u094d\u0937 \u092e\u093e\u0902 \u0936\u0930\u0923\u093e\u0917\u0924\u092e\u094d\u0964',roman:'Apnnosmi Shrnyosmi Srvavsthasu Srvda. Bhgvn Tvam Prpnnosmi Rksh Mam Shrnagtm.',english:'Oh God, I am always waiting for your mercy. Please take me under your care and protect me who has surrendered to you.'},isOptional:!1,duration:30},{id:'C2',number:2,title:{devanagari:'\u0928\u093e\u0930\u093f\u0935\u0928 / \u0930\u0915\u094d\u0937\u093e \u0938\u0942\u0924\u094d\u0930 \u092c\u0928\u094d\u0927\u0928',roman:'Nariwan / Raksha Sutra Bandhan',english:'Tying the Sacred Thread'},instructions:'Tie the Nariwan (which was the object of worship) around the right wrist for males, left wrist for females. This is the Raksha Sutra (protection thread) and should be kept until the next birthday. All family members present receive their pre-cut nariwan pieces.',actionDescription:'Tie Nariwan on wrist (right=male, left=female)',mantra:{devanagari:'\u092f\u0947\u0928 \u092c\u0926\u094d\u0927\u094b \u092c\u0932\u0940 \u0930\u093e\u091c\u093e \u0926\u093e\u0928\u0935\u0947\u0928\u094d\u0926\u094d\u0930\u094b \u092e\u0939\u093e\u092c\u0932\u0903\u0964 \u0924\u0947\u0928 \u0924\u094d\u0935\u093e\u0902 \u092a\u094d\u0930\u0924\u093f\u092c\u0927\u094d\u0928\u093e\u092e\u093f \u0930\u0915\u094d\u0937\u0947 \u092e\u093e \u091a\u0932 \u092e\u093e \u091a\u0932\u0964',roman:'Yena Baddho Bali Raja Danavendro Mahabalah. Tena Tvam Pratibadhnami Rakshe Ma Chal Ma Chal.',english:'With this thread that bound the mighty King Bali, I bind you. O protector, do not waver, do not waver.'},isOptional:!1,duration:60}]}]}},513,[]);
